        let dir = tempfile::tempdir().unwrap();
        let store = Arc::new(LiteStore::open(dir.path(), 3).unwrap());
        store.init_schema().await.unwrap();
        let engine: Arc<dyn InferenceEngine> = Arc::new(MockEngine);

